    _ses_c = _ses_segs.GetItemAsObject(_ses_i)
    if _ses_c is not None and _ses_c.GetAttribute("SlicerAIAgent.SegmentEditorSession") == "1":
        _ses_seg = _ses_c
        break
if _ses_seg is None:
    for _ses_i in range(_ses_segs.GetNumberOfItems() - 1, -1, -1):
        _ses_c = _ses_segs.GetItemAsObject(_ses_i)
